#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MOD 1000000007

long long pow_mod(long long base, long long exp, long long mod) {
    long long result = 1;
    while (exp > 0) {
        if (exp % 2 == 1) {
            result = (result * base) % mod;
        }
        base = (base * base) % mod;
        exp /= 2;
    }
    return result;
}

void process() {
    int P, K;
    scanf("%d %d", &P, &K);
    int *k = (int *)malloc(P * sizeof(int));
    for (int x = 0; x < P; x++) {
        k[x] = (K * x) % P;
    }
    if (K == 0) {
        printf("%lld\n", pow_mod(P, P - 1, MOD));
        free(k);
        return;
    }
    int *visited = (int *)calloc(P, sizeof(int));
    int *cycle_len_count = (int *)calloc(P, sizeof(int));
    long long result = 1;
    for (int start = 0; start < P; start++) {
        if (visited[start]) {
            continue;
        }
        int length = 1;
        int current = start;
        visited[current] = 1;
        while (!visited[k[current]]) {
            current = k[current];
            visited[current] = 1;
            length++;
        }
        cycle_len_count[length]++;
    }
    for (int length = 1; length < P; length++) {
        int count = cycle_len_count[length];
        if (count == 0) {
            continue;
        }
        int total = length * count + (length > 1 ? cycle_len_count[1] : 0);
        result = result * pow_mod(total, count, MOD) % MOD;
    }
    printf("%lld\n", result);
    free(k);
    free(visited);
    free(cycle_len_count);
}

int main() {
    int T = 1;
    for (int _ = 0; _ < T; _++) {
        process();
    }
    return 0;
}
